          <Box key={id}>
            <Text color={i === cursor ? '#a78bfa' : undefined} bold={i === cursor}>
              {i === cursor ? ' \u276f ' : '   '}
            </Text>
            <Text color={i === cursor ? '#a78bfa' : undefined} bold={i === cursor}>
              {id}
            </Text>
            {id === currentCesar && <Text color="green">{' ' + icons().success + ' current'}</Text>}
          </Box>
